{
  "name": "KanCare Frail Elderly Waiver (FE Waiver)",
  "eligibility": {
    "age": 65,
    "income_limits": "No set income limit for the waiver, but beneficiaries keep $2,982 per month of their income (2026 amount). Income eligibility determined through underlying KanCare Medicaid categories such as SSI, 300% SSI, TANF, or Medically Needy.[1][2][6]",
    "asset_limits": "Standard Kansas Medicaid asset limit applies (specific dollar amount not stated in sources; use KanCare Spend Down Calculator for estimates). Countable assets exclude primary home (if equity ≤ $752,000 in 2026, applicant lives there or intends to return, spouse/minor/disabled child resides there), household furnishings, appliances, personal effects, and one vehicle. 60-month Look-Back Rule penalizes asset transfers below fair market value.[1]",
    "other_requirements": [
      "Kansas resident",
      "Eligible for KanCare (Kansas Medicaid)",
      "Nursing Facility Level of Care (NFLOC) determined via Functional Assessment Instrument (FAI), evaluating Activities of Daily Living (ADLs: toileting, bathing, dressing, transferring, mobility, eating) and Instrumental ADLs (IADLs: cleaning, cooking, shopping, paying bills), plus cognitive/behavioral issues.[1][2][3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Home and Community-Based Services (HCBS) as alternative to nursing home care, including variety of services authorized via Plan of Care (POC) process to meet individual needs. Specific services not exhaustively listed but designed for frail elderly 65+ to avoid institutionalization; does not cover room/board or living expenses.[4][5]",
    "varies_by": "individual_needs"
  },
  "application": {
    "methods": [
      "Contact Kansas Department for Aging and Disability Services (KDADS) or local waiver program manager for preliminary functional eligibility application (specific phone/website not in results; enroll via fiscal agent for providers).[3][4]",
      "Apply for underlying KanCare Medicaid first"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Waitlist (proposed recipient list) maintained when no openings exist; limited slots.[3]",
    "forms": [
      "Preliminary functional eligibility application (filed with waiver program manager)",
      "Specific waiver eligibility assessment and re-assessments for Level of Care (LOC)[3][4]"
    ],
    "documents": [
      "Proof of KanCare Medicaid eligibility",
      "Documentation for NFLOC/FAI assessment (ADLs/IADLs/cognitive details)",
      "Financial records for income/assets (use Spend Down Calculator if needed)",
      "LOC documentation as requested (e.g., medical assessments)[1][4]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None specified; serves Kansas residents statewide",
    "regional_variations": "Wait times may vary regionally due to limited slots and local providers, but no specific differences detailed.[3]",
    "offices_or_providers": [
      "Managed by Kansas Department for Aging and Disability Services (KDADS); providers enroll via fiscal agent (KMAP); delivered through Managed Care Organizations (MCOs) like Sunflower Health Plan[4][5]"
    ]
  },
  "official_source": "https://khap.kdhe.ks.gov/KEESM/Oct_2020_Output/keesm8210.htm (KDHE policy) or https://portal.kmap-state-ks.us/Documents/Provider/Provider%20Manuals/HCBS_FE_24281_24277.pdf (HCBS FE Provider Manual)",
  "gotchas": [
    "Must first qualify for KanCare Medicaid; waiver denial if not financially eligible upfront.[2]",
    "60-month Look-Back Rule on asset transfers leads to penalty periods.[1]",
    "Limited slots create waitlists; not guaranteed immediate access.[3]",
    "Services require prior authorization via POC; no coverage for room/board.[4][5]",
    "Home equity limit $752,000 (2026); intent to return must be documented.[1]"
  ],
  "data_shape_notes": "No fixed income limit but patient liability of $2,982/month (2026); NFLOC via FAI assessment; statewide with waitlist due to slot limits; home equity exemption with $752,000 cap"
}

{
  "name": "KanCare Medicare Savings Programs (QMB, SLMB, QI)",
  "eligibility": {
    "age": null,
    "income_limits": "Must be eligible for or enrolled in Medicare Part A (typically age 65+ or disabled). Income limits vary by program and are monthly gross income including $20 disregard; limits updated annually (2025 figures from [5]): QMB - Single: $1,255, Couple: $1,704; SLMB - Single: $1,506, Couple: $2,044; QI - Single: $1,695, Couple: $2,300. Older sources show lower prior-year limits (e.g., 2022 QMB single $1,153 [2]). No variation by larger household sizes; based on individual or couple.[1][2][4][5][7]",
    "asset_limits": "Countable resources (2025): $9,660 individual, $14,470 couple. Exempt: primary residence, vehicles, up to $1,500/person burial funds. What counts: bank accounts, stocks, non-exempt cash (limits consistent across programs; older sources ~$9,430 single/$14,130 couple).[1][4][5]",
    "other_requirements": ["Must have or be eligible for Medicare Part A.", "U.S. citizen or qualified immigrant.", "Kansas resident.", "Not receiving inpatient TB treatment or other conflicting aid (general KanCare rules)."][3][5][6]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part A/B premiums, deductibles, coinsurance, copayments for Medicare-covered services. SLMB/QI: Pays Part B premium only. Automatic Extra Help for Part D prescription drugs if qualified for any.[1][2][3][4][5]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: kancare.ks.gov/apply-now [6]", "Phone: 1-800-792-4884 to request paper form [7]", "Mail: KanCare, PO Box 3599, Topeka, KS 66601 [7]", "Fax paper form to KanCare Clearinghouse: 844-264-6285 [5]", "In-person: Local KDHE/KanCare eligibility office (statewide via KanCare) [6]"],
    "processing_time": "Not specified in sources; typically 45 days for Medicaid-like programs but confirm with KanCare.",
    "waitlist": null,
    "forms": ["Application/Re-determination Medicare Savings Program (print from KanCare website) [5][7]"],
    "documents": ["Proof of income (SSI award, pay stubs, Social Security statements)", "Proof of resources (bank statements)", "Medicare card or proof of Part A eligibility", "ID (birth certificate, Social Security card)", "Proof of residency", "Household composition details."][5][6]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by KanCare; no specific regional differences, providers, or wait times noted. Local Area Agencies on Aging (e.g., NEKAAA) provide info but eligibility uniform.[2][6]",
    "offices_or_providers": []
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/medicare-programs/senior-health-insurance-counseling-for-kansas-shick/medicare-part-d-prescription-drug-coverage/medicare-frequently-asked-questions [5]; https://www.kancare.ks.gov/apply-now/eligibility [6]",
  "gotchas": ["Limits change yearly; always verify current via 1-800-792-4884 [7]. QMB offers most coverage (copays/deductibles) vs SLMB/QI (premiums only) [1][2]. Automatic Extra Help for Part D but must apply for MSP first [2][3]. Assets exclude home/vehicles/burial but include most cash/stocks [5]. Income is gross monthly with $20 disregard [4]. Must use other insurance first [6]. No larger household multipliers beyond couple [1]."],
  "data_shape_notes": "Three tiers (QMB, SLMB, QI) with escalating income limits but fixed asset limits; couple vs single only (no larger households); annual updates; automatic Part D linkage; statewide uniform."
}

{
  "name": "Senior Health Insurance Counseling for Kansas (SHICK)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to anyone with Medicare questions, including older Kansans, people with disabilities, and caregivers[1][2][4][6][8]",
    "asset_limits": "No asset limits or tests apply[2][8]",
    "other_requirements": ["Open to individuals with Medicare, those preparing to enroll, people with disabilities, caregivers, and families; no affiliation requirement beyond having Medicare-related questions[1][2][4][6][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, one-on-one counseling on Medicare (Parts A-D), Medicare Supplement (Medigap), Medicare Advantage, prescription drug coverage (Part D), Extra Help, long-term care insurance, claims/appeals, supplemental rate comparisons, employer group plans, Medicaid, employment/disability Medicare info; public education presentations; available Monday-Friday, typically 8:30am-3pm or 8am-5pm depending on location[1][2][3][4][5][7][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-860-5260 (statewide toll-free)[2][3][8][9]", "Regional/local contacts (e.g., Sedgwick: 316-660-0126[1], Johnson County: 913-715-8856[5], North Central: 1-800-432-2703[6])", "Website: https://www.kdads.ks.gov/services-programs/aging/medicare-programs/senior-health-insurance-counseling-for-kansas-shick[2][3]", "In-person: Through local Area Agencies on Aging or SHICK partners statewide (e.g., Wichita, Kansas City)[1][5][6][8]", "Email: christina.orton2@ks.gov[3]"],
    "processing_time": "Counseling appointments scheduled by phone; no formal processing as it's direct service, but busy during Open Enrollment (mid-Oct to early Dec)[6]",
    "waitlist": null,
    "forms": ["No specific forms required; schedule appointment directly[2][4][5]"],
    "documents": ["Medicare card, current insurance documents, prescription lists recommended for personalized counseling but not mandatory[7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Kansas[2][3][6][7]",
    "regional_variations": "Delivered through local Area Agencies on Aging and community partners with regional counselors and contact numbers; availability and hours may vary slightly by location (e.g., Sedgwick 8:30am-3pm, state office 8am-5pm)[1][3][5][6][8]",
    "offices_or_providers": ["Kansas Department for Aging and Disability Services, 503 S. Kansas Ave, Topeka, KS 66603[3][8]", "Local: Central Plains AAA (Wichita, 800-367-7298 ext. 5132), Wyandotte/Leavenworth AAA (Kansas City, 888-661-1444), NC-FH AAA (18-county region)[6][8]"]
  },
  "official_source": "https://www.kdads.ks.gov/services-programs/aging/medicare-programs/senior-health-insurance-counseling-for-kansas-shick",
  "gotchas": ["Counselors are volunteers, not insurance agents, and unaffiliated with industry—cannot sell plans[1][2][8]", "Peak demand during Medicare Open Enrollment (Oct-Dec) may limit immediate appointments[6]", "Not a healthcare provider or financial aid program—only counseling and education[2][7]", "Must schedule appointments; no walk-ins specified[1][4][5]"],
  "data_shape_notes": "no income/asset test; volunteer-delivered statewide counseling service via local Area Agencies on Aging; part of federal SHIP network"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are set by federal poverty guidelines (not specified in sources for current year; check DOL for latest table).[2][6]",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Poor employment prospects", "Priority to veterans and qualified spouses, individuals over 65, those with disabilities, low literacy, limited English proficiency, rural residents, homeless or at risk, low employment prospects, or prior American Job Center users"][2]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work (average 20 hours/week) at nonprofit/public facilities (schools, hospitals, day-care, senior centers); paid highest of federal/state/local minimum wage; on-the-job training in skills (e.g., digital literacy, vocational); job placement assistance to unsubsidized employment; supportive services (dental, vision, clothing, transportation).[2][3][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Wichita Workforce Center at (316) 771-6750 or SCSEP team at 316-771-6750", "In-person: Wichita Workforce Center, 2021 N. Amidon, #1100, Wichita, KS 67203", "Contact Jobs for Progress National (SER Jobs for Progress, operator in Kansas)", "Access via American Job Centers"],
    "processing_time": null,
    "waitlist": null,
    "forms": [],
    "documents": ["Proof of age, income, unemployment status, and priority factors (e.g., veteran status, disability documentation) – prepare but confirm with provider"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Operated by grantees like SER Jobs for Progress (covers Kansas counties) and Wichita Workforce Center; contact local providers for regional access.[1][5][6]",
    "offices_or_providers": ["Wichita Workforce Center (316-771-6750)", "SER Jobs for Progress National (SCSEP operator in Kansas)"]
  },
  "official_source": "https://workforce-ks.com/programs/seniorcommunityserviceemploymentprogram/",
  "gotchas": ["Income must be ≤125% federal poverty level (not just 'low-income'); it's training-to-employment bridge, not permanent job or welfare; priority tiers may delay non-priority applicants; operated by multiple grantees (e.g., SER, AARP Foundation), so check Kansas-specific provider; no guaranteed placement time.[2][6]"],
  "data_shape_notes": "Federally uniform but locally administered by grantees (SER in Kansas); income tied to annual federal poverty guidelines table; priority enrollment tiers; no fixed asset limits or forms specified"
}

{
  "name": "Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; open to all seniors age 60+ regardless of income.[2][3]",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Kansas resident age 60 or older.", "Civil legal issues only, with priority for at-risk elderly in greatest social/economic need (e.g., cash/medical assistance, elder abuse)."]
  },
  "benefits": {
    "type": "service",
    "value": "Legal counseling and referral at no cost; legal representation for certain court appearances, administrative negotiation, and drafting of legal documents; advice on civil legal issues; referrals to local Senior Citizens Law Project attorneys or private attorneys; public education on elders' rights.[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: Elder Law Hotline toll-free 1-888-353-5337 (8:30 a.m.-5:00 p.m. Mon-Fri) or (785) 336-6016 (Northeast Kansas); Kansas Legal Services 316-267-3975 or toll-free 800-723-6953 (8:00 a.m.-4:30 p.m. Mon-Fri).[1][3][8]",
      "Online: Kansas Legal Services online application at their Get Help page.[8]",
      "In-person: Staff attorney visits to communities or at-home visits can be arranged; local Kansas Legal Services offices statewide.[1][3]"
    ],
    "processing_time": "Attorney reviews information and contacts as soon as possible; no specific timeline stated.[1]",
    "waitlist": "Not mentioned.",
    "forms": ["Intake by phone; online application through Kansas Legal Services.[1][8]"],
    "documents": ["Not specified; intake specialist takes basic information over phone for attorney review."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Kansans statewide, including rural areas via hotline.[2][3]",
    "regional_variations": "Services delivered through local Senior Citizens Law Project offices and Area Agencies on Aging (e.g., Northeast Kansas example); community/at-home visits available regionally.[1][3]",
    "offices_or_providers": ["Kansas Legal Services offices throughout the state; Northeast Kansas Area Agency on Aging (785-336-6016); cooperates with Kansas Department on Aging and Area Agencies on Aging."]
  },
  "official_source": "https://www.kansaslegalservices.org/page/57/programs-seniors",
  "gotchas": [
    "No income eligibility required for hotline, but full representation prioritizes at-risk/low-income seniors.[2][3]",
    "Not all cases accepted; may be referred to private pro bono attorneys if conflicts or barriers exist.[2]",
    "Civil issues only; focuses on elder abuse, benefits access, rights—not criminal matters.",
    "Volunteers handle hotline; expect varying attorney availability.[2]"
  ],
  "data_shape_notes": "No income/asset test; priority-based for at-risk seniors; delivered statewide via hotline and local projects with Area Agencies on Aging; pro bono volunteer-driven."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a long-term care facility in Kansas (nursing homes, assisted living facilities, board and care homes, home plus facilities, adult day care centers, residential healthcare facilities). Services can be requested by or on behalf of the resident with resident consent for investigations."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Independent advocacy including identifying, investigating, and resolving complaints; providing information on long-term care services and resident rights; representing residents before agencies for administrative, legal, or other remedies; regular presence in facilities to observe care and ensure access; addressing issues like improper discharges, medication errors, abuse, staffing, food service, daily care, privacy, and dignity.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-877-662-8362 or local (785) 296-3017", "Email: LTCO@ks.gov", "Website: https://www.ombudsman.ks.gov (find regional ombudsman, submit complaint online, or contact for assistance)", "In-person: Contact regional ombudsman office via https://www.ombudsman.ks.gov/find-your-ombudsman"],
    "processing_time": "Not specified; ombudsmen respond to complaints as needed, with regular facility visits.",
    "waitlist": null,
    "forms": ["No specific application form required for residents; use Volunteer Ombudsman Application only if becoming a volunteer. Complaints handled directly via phone/email/contact form."],
    "documents": ["No documents needed to request services; resident consent required for complaint investigations. Provide details of concern (e.g., facility name, issue description)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in certified long-term care facilities across Kansas.",
    "regional_variations": "Delivered through regional ombudsman offices with local staff and volunteers; find specific office via https://www.ombudsman.ks.gov/find-your-ombudsman. No specified differences in services, but contact and hours may vary by region.",
    "offices_or_providers": ["Regional Long-Term Care Ombudsmen listed at https://www.ombudsman.ks.gov/find-your-ombudsman"]
  },
  "official_source": "https://www.ombudsman.ks.gov",
  "gotchas": ["Not a financial or direct service program—provides advocacy only, not healthcare, housing, or payments. Requires resident consent for actions. Distinct from KanCare Ombudsman (for Medicaid issues). Volunteers need training and screening, but residents do not apply to 'qualify'—anyone can contact for help. Not for community-dwelling elderly outside facilities."],
  "data_shape_notes": "no income test; advocacy-only for facility residents; regional delivery model; open to all without eligibility barriers"
}
